"use client";

import { useCallback, useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { logoutAndClearAuthSession } from "@/services/authSession.service";
import {
  DASHBOARD_MODE_BUSINESS,
  DASHBOARD_MODE_USER,
  getDashboardMode,
  isBusinessRegistered,
  setDashboardMode,
} from "@/services/dashboardMode.service";

export default function BrokerDashboardPage() {
  const router = useRouter();
  const [loggingOut, setLoggingOut] = useState(false);

  useEffect(() => {
    if (!isBusinessRegistered()) {
      router.replace("/home");
      return;
    }
    if (getDashboardMode() !== DASHBOARD_MODE_BUSINESS) {
      setDashboardMode(DASHBOARD_MODE_BUSINESS);
    }
  }, [router]);

  const handleLogout = useCallback(async () => {
    try {
      setLoggingOut(true);
      setDashboardMode(DASHBOARD_MODE_USER);
      await logoutAndClearAuthSession();
    } finally {
      router.replace("/home");
    }
  }, [router]);

  return (
    <main className="min-h-screen bg-slate-100 px-4 py-10 sm:px-6 md:py-14">
      <div className="mx-auto max-w-4xl rounded-2xl border border-slate-200 bg-white p-6 shadow-md sm:p-8">
        <h1 className="text-4xl font-bold text-slate-900">Business Dashboard</h1>
        <p className="mt-4 max-w-3xl text-2xl leading-relaxed text-slate-600">
          Business-related admin actions are coming soon. You&apos;ll manage branches, menus,
          subscriptions, and more from here once they&apos;re ready.
        </p>
        <button
          type="button"
          onClick={handleLogout}
          disabled={loggingOut}
          className="mt-8 flex h-14 w-full items-center justify-center rounded-xl bg-gradient-to-r from-slate-800 to-blue-950 text-xl font-semibold text-white transition hover:brightness-110 disabled:cursor-not-allowed disabled:opacity-70"
        >
          {loggingOut ? "Logging out..." : "Logout"}
        </button>
      </div>
    </main>
  );
}
